const nodeCrypto=require("crypto");module.exports={postgresMd5PasswordHash:postgresMd5PasswordHash,randomBytes:randomBytes,deriveKey:deriveKey,sha256:sha256,hashByName:hashByName,hmacSha256:hmacSha256,md5:md5};const webCrypto=nodeCrypto.webcrypto||globalThis.crypto,subtleCrypto=webCrypto.subtle,textEncoder=new TextEncoder;function randomBytes(t){return webCrypto.getRandomValues(Buffer.alloc(t))}async function md5(t){try{return nodeCrypto.createHash("md5").update(t,"utf-8").digest("hex")}catch(e){const r="string"==typeof t?textEncoder.encode(t):t,a=await subtleCrypto.digest("MD5",r);return Array.from(new Uint8Array(a)).map((t=>t.toString(16).padStart(2,"0"))).join("")}}async function postgresMd5PasswordHash(t,e,r){const a=await md5(e+t);return"md5"+await md5(Buffer.concat([Buffer.from(a),r]))}async function sha256(t){return await subtleCrypto.digest("SHA-256",t)}async function hashByName(t,e){return await subtleCrypto.digest(t,e)}async function hmacSha256(t,e){const r=await subtleCrypto.importKey("raw",t,{name:"HMAC",hash:"SHA-256"},!1,["sign"]);return await subtleCrypto.sign("HMAC",r,textEncoder.encode(e))}async function deriveKey(t,e,r){const a=await subtleCrypto.importKey("raw",textEncoder.encode(t),"PBKDF2",!1,["deriveBits"]),o={name:"PBKDF2",hash:"SHA-256",salt:e,iterations:r};return await subtleCrypto.deriveBits(o,a,256,["deriveBits"])}